import { useFocusEffect, useNavigation } from '@react-navigation/native';
import { NativeStackNavigationProp } from '@react-navigation/native-stack';
import React, { useCallback, useContext, useMemo, useState } from 'react';
import { Pressable, SafeAreaView, ScrollView, StyleSheet, Text, View } from 'react-native';
import { AuthContext } from '../../App';
import AppIcon from '../components/AppIcon';
import CustomerBottomNav from '../components/CustomerBottomNav';
import OrderStatusTracker from '../components/OrderStatusTracker';
import ScreenHeader from '../components/ScreenHeader';
import {
  formatCurrency,
  formatOrderDate,
  formatOrderNumber,
  getReminderText,
  getSuggestedQuantity,
  ORDER_STATUS_META,
  WATER_PRODUCT
} from '../data/orderModule';
import { RootStackParamList } from '../navigation/AppNavigator';
import { fetchCustomerOrders, OrderRecord } from '../services/firebaseService';
import { createShadow } from '../styles/shadows';
import { theme } from '../styles/theme';

type NavigationProp = NativeStackNavigationProp<RootStackParamList, 'CustomerHome'>;

const CustomerHomeScreen = () => {
  const { profile } = useContext(AuthContext);
  const navigation = useNavigation<NavigationProp>();
  const [orders, setOrders] = useState<OrderRecord[]>([]);

  useFocusEffect(
    useCallback(() => {
      let active = true;
      const loadOrders = async () => {
        if (!profile?.uid) {
          setOrders([]);
          return;
        }
        const data = await fetchCustomerOrders(profile.uid).catch(() => []);
        if (active) {
          setOrders(data);
        }
      };

      loadOrders();
      return () => {
        active = false;
      };
    }, [profile?.uid])
  );

  const activeOrder =
    orders.find((order) => ['pending', 'confirmed', 'preparing', 'out_for_delivery'].includes(order.status)) ?? null;
  const reminderText = useMemo(() => getReminderText(orders), [orders]);
  const suggestedQuantity = getSuggestedQuantity(orders);
  const lastOrder = orders[0] ?? null;
  const approvedText =
    profile?.role === 'customer' ? (profile.approved ? 'Ordering unlocked' : 'Waiting for approval') : 'Owner account';

  return (
    <SafeAreaView style={styles.container}>
      <ScrollView contentContainerStyle={styles.content} showsVerticalScrollIndicator={false}>
        <ScreenHeader
          eyebrow={`Hello ${profile?.name?.split(' ')[0] || 'Customer'}`}
          title="Your water dashboard"
          subtitle="An iPhone-style home screen with fast actions, order status, reminders, and account context."
          profile
        />

        <View style={styles.heroCard}>
          <View style={styles.heroTop}>
            <View style={styles.heroBadge}>
              <AppIcon name="water" size={16} color={theme.colors.primary} />
              <Text style={styles.heroBadgeText}>20L Premium cans</Text>
            </View>
            <View style={styles.heroBadge}>
              <AppIcon name={profile?.approved ? 'checkmark-circle' : 'time-outline'} size={16} color={profile?.approved ? theme.colors.secondary : theme.colors.warning} />
              <Text style={styles.heroBadgeText}>{approvedText}</Text>
            </View>
          </View>
          <Text style={styles.heroTitle}>Fresh water, clear steps, and everything in one place.</Text>
          <Text style={styles.heroSubtitle}>
            Order now, check the next delivery, review your last order, and jump straight into plans or payments.
          </Text>
          <View style={styles.heroActionRow}>
            <Pressable style={styles.primaryButton} onPress={() => navigation.navigate('NewOrder')}>
              <AppIcon name="add-circle-outline" size={18} color="#fff" />
              <Text style={styles.primaryButtonText}>New order</Text>
            </Pressable>
            <Pressable style={styles.secondaryButton} onPress={() => navigation.navigate('CustomerOrders')}>
              <AppIcon name="receipt-outline" size={18} color={theme.colors.primary} />
              <Text style={styles.secondaryButtonText}>My orders</Text>
            </Pressable>
          </View>
        </View>

        <View style={styles.metricsRow}>
          <View style={styles.metricCard}>
            <AppIcon name="pricetag-outline" size={18} color={theme.colors.primary} />
            <Text style={styles.metricValue}>{formatCurrency(WATER_PRODUCT.pricePerCan)}</Text>
            <Text style={styles.metricLabel}>Per can</Text>
          </View>
          <View style={styles.metricCard}>
            <AppIcon name="cube-outline" size={18} color={theme.colors.secondary} />
            <Text style={styles.metricValue}>{WATER_PRODUCT.availableStock}</Text>
            <Text style={styles.metricLabel}>In stock</Text>
          </View>
          <View style={styles.metricCard}>
            <AppIcon name="repeat-outline" size={18} color={theme.colors.warning} />
            <Text style={styles.metricValue}>{orders.length}</Text>
            <Text style={styles.metricLabel}>All orders</Text>
          </View>
        </View>

        <View style={styles.reminderCard}>
          <View style={styles.cardTitleRow}>
            <Text style={styles.cardTitle}>Smart reminder</Text>
            <AppIcon name="notifications-outline" size={18} color={theme.colors.textSecondary} />
          </View>
          <Text style={styles.reminderText}>{reminderText}</Text>
          <Pressable style={styles.inlineAction} onPress={() => navigation.navigate('NewOrder', { reorder: true })}>
            <Text style={styles.inlineActionText}>Reorder {suggestedQuantity} cans</Text>
            <AppIcon name="arrow-forward" size={16} color={theme.colors.primary} />
          </Pressable>
        </View>

        {activeOrder ? (
          <View style={styles.card}>
            <View style={styles.cardTitleRow}>
              <View>
                <Text style={styles.cardTitle}>Current order</Text>
                <Text style={styles.cardSubtitle}>
                  {formatOrderNumber(activeOrder)} • {formatCurrency(activeOrder.totalAmount)}
                </Text>
              </View>
              <Pressable style={styles.smallAction} onPress={() => navigation.navigate('OrderTracking', { orderId: activeOrder.id })}>
                <Text style={styles.smallActionText}>Track</Text>
              </Pressable>
            </View>
            <OrderStatusTracker status={activeOrder.status} compact />
            <View style={styles.infoTiles}>
              <View style={styles.infoTile}>
                <Text style={styles.infoTileLabel}>Quantity</Text>
                <Text style={styles.infoTileValue}>{activeOrder.quantity} cans</Text>
              </View>
              <View style={styles.infoTile}>
                <Text style={styles.infoTileLabel}>ETA</Text>
                <Text style={styles.infoTileValue}>{activeOrder.expectedDeliveryTime}</Text>
              </View>
            </View>
          </View>
        ) : (
          <View style={styles.card}>
            <View style={styles.emptyIconWrap}>
              <AppIcon name="checkmark-done-circle-outline" size={24} color={theme.colors.primary} />
            </View>
            <Text style={styles.cardTitle}>No active delivery</Text>
            <Text style={styles.cardSubtitle}>Your next active order will appear here with live tracking details.</Text>
          </View>
        )}

        <View style={styles.doubleRow}>
          <View style={[styles.card, styles.halfCard]}>
            <View style={styles.cardTitleRow}>
              <Text style={styles.cardTitle}>Quick reorder</Text>
              <AppIcon name="flash-outline" size={18} color={theme.colors.warning} />
            </View>
            {lastOrder ? (
              <>
                <Text style={styles.summaryHeadline}>{formatOrderNumber(lastOrder)}</Text>
                <Text style={styles.cardSubtitle}>{lastOrder.quantity} cans • {formatOrderDate(lastOrder.createdAt)}</Text>
                <Pressable style={styles.inlineAction} onPress={() => navigation.navigate('NewOrder', { reorder: true })}>
                  <Text style={styles.inlineActionText}>Order again</Text>
                  <AppIcon name="arrow-forward" size={16} color={theme.colors.primary} />
                </Pressable>
              </>
            ) : (
              <Text style={styles.cardSubtitle}>Once you place your first order, it will be ready here for one-tap reorder.</Text>
            )}
          </View>

          <View style={[styles.card, styles.halfCard]}>
            <View style={styles.cardTitleRow}>
              <Text style={styles.cardTitle}>Subscription</Text>
              <AppIcon name="calendar-outline" size={18} color={theme.colors.secondary} />
            </View>
            <Text style={styles.cardSubtitle}>Create a recurring plan so you do not need to book every time.</Text>
            <Pressable style={styles.inlineAction} onPress={() => navigation.navigate('CustomerSubscription')}>
              <Text style={styles.inlineActionText}>Open plan</Text>
              <AppIcon name="arrow-forward" size={16} color={theme.colors.primary} />
            </Pressable>
          </View>
        </View>

        {lastOrder ? (
          <View style={styles.card}>
            <View style={styles.cardTitleRow}>
              <Text style={styles.cardTitle}>Recent order summary</Text>
              <AppIcon name="document-text-outline" size={18} color={theme.colors.textSecondary} />
            </View>
            <Text style={styles.summaryHeadline}>{formatOrderNumber(lastOrder)}</Text>
            <View style={styles.summaryList}>
              <Text style={styles.summaryItem}>Status: {ORDER_STATUS_META[lastOrder.status].label}</Text>
              <Text style={styles.summaryItem}>Amount: {formatCurrency(lastOrder.totalAmount)}</Text>
              <Text style={styles.summaryItem}>Payment: {lastOrder.paymentMethod}</Text>
            </View>
          </View>
        ) : null}
      </ScrollView>
      <CustomerBottomNav active="CustomerHome" />
    </SafeAreaView>
  );
};

